                        <td><a href="@Url.Action("FailuresSummary","Reports", new { Area = "Production", dateStart = Model.dateStart, dateEnd = Model.dateEnd, selectedCustomers = "", selectedPartNo = rowstation["PartNumber"].ToString(),StationId=Model.StationID,AreaID=Model.AreaID,ssnindex=1,execute=true,prepareDownload=Model.prepareDownload,AreaName =rowstation["Area"].ToString() })">@cell.ToString()</a></td>
