                          backgroundColor: 'rgb(68,206,27,0.3)',
                          borderColor: 'rgba(68,206,27, 1)',
                        },
                        {
                          label: 'Bad',
                          data: [@rowstation["Bad"].ToString(),@rowstation["2ndBad"].ToString(),@rowstation["AccumBad"].ToString()],
                          backgroundColor: 'rgb(229, 31, 31,0.3)',
                          borderColor: 'rgba(229, 31, 31, 1)',
                        }
                      ]
                    };

                    var ctFalsesTOP10_@ii = document.getElementById("chartFalsesTOP10_@ii").getContext("2d");
                    var myFalsesTOP10_@ii = new Chart(ctFalsesTOP10_@ii, {
                      type: 'bar',
                      data: data_@ii,
                      options: {
                        scales: {
                          xAxes: [{
                            stacked: true
