<script type="text/javascript" nonce="@Html.ScriptNonce()">
  function FillStations() {
    var AreaID = $('#ddlareaid').val();
    var req2 = { AreaID: AreaID, All: 'ALL' };
    $.ajax({
      type: "POST",
      url: "/Manage/Areas/FillStations",
      async: false,
      contentType: "application/json; charset=utf-8",
      data: JSON.stringify(req2),
      success: function (response) {
        //console.log(response);
        $("#ddlsubstation").html("");
        $.each(response, function (index, value) {
          $("#ddlsubstation").append(
            $('<option></option>').val(value.Value).html(value.Text));
        });
      },
      error: function () {
        $("#ddlsubstation").html("");
        $("#ddlsubstation").append(
          $('<option></option>').val(0).html("NA"));
      }
    });
  }
</script>


<script type="text/javascript" nonce="@Html.ScriptNonce()">
  document.getElementById("btnExport").addEventListener('click', function () {

    $("body").addClass("loading");

    /* Create worksheet from HTML DOM TABLE */
    var wb = XLSX.utils.table_to_book(document.getElementById("ExportDetails"));
    /* Export to file (start a download) */
    const d = new Date();
    let text = moment(d).format('YYYYMMDDHHMMSS');

    XLSX.writeFile(wb, "Serials" + text + ".xlsx");

    $("body").removeClass("loading");
  });
</script>

