@using NonFactors.Mvc.Grid;
@using System.Data;
@using System.Data.SqlClient;
@using System.Globalization;
@using Firstronic.Framework.Charts;


@model Firstronic.Areas.Production.Models.Reports.ProductionSummary

@section head{
  <script src="~/Content/vendor/d3/d3.v4.min.js"></script>
  <script src="~/Content/vendor/chartjs/Chart.min.js"></script>
  <script src="~/Content/vendor/xlsx/xlsx.full.min.js"></script>
}

<div class="md-card">
  <div class="md-card-toolbar">
    <h3 class="md-card-toolbar-heading-text"> Successes Details </h3>
  </div>

  <div class="md-card-content">
    @if (Model.execute == true)
    {
      ViewBag.Title = Model.Part_No;

      var dateStart = Model.dateStart.GetValueOrDefault().AddHours(+6);

      var dateEnd = Model.dateEnd.GetValueOrDefault().AddHours(+6).AddDays(+1);

      DataTable dtResult = new DataTable();

      if (Model.selectedCustomers == "" && Model.selectedPartID == "")
      {
        Model.selectedCustomers = ",0,";
        Model.selectedPartID = "";
      }

      var Customers = Model.selectedCustomers.ToString().Split(',');

      SqlParameter[] partParameters = new SqlParameter[]
      {
        new SqlParameter("@PartNumber",SqlDbType.VarChar){Value = Model.selectedPartID}
                };

      int PartId = Firstronic.Framework.Queries.GetIntFromQuery("SELECT [PartID] FROM [CS_IDT_PARTNUMBERS] where partnumber=@PartNumber", partParameters);

      var PartIDS = PartId.ToString().Split(',');

      foreach (var PartID in PartIDS)
      {
        if (PartID != "")
        {
          Customers = ",,".Split(',');
        }
      }

      DataTable dtSerials = new DataTable();

      foreach (var PartID in PartIDS)
      {
        if (PartID != "")
        {
          SqlParameter[] parameters = new SqlParameter[]
          {
            new SqlParameter("@AreaID",SqlDbType.Int){Value = Model.AreaID},
            new SqlParameter("@StationID",SqlDbType.Int){Value = Model.StationID},
            new SqlParameter("@PartID",SqlDbType.Int){Value = PartID},
            new SqlParameter("@dateStart",SqlDbType.DateTime){Value =dateStart.ToString("MM/dd/yyyy HH:mm:ss")},
            new SqlParameter("@dateEnd",SqlDbType.DateTime){Value =dateEnd.ToString("MM/dd/yyyy HH:mm:ss")}
                    };

          DataTable dtAreaSTATIONPART = Firstronic.Framework.Queries.GetDatatableFromQuery(@"WITH w AS (
SELECT
ut.SSN AS UnitID,
ut.TrnDate,
pn.PartNumber,
a.Area,
ec.CustomerName,
ut.JobSide,
ISNULL(pb.Bin_Name, '') AS Bin_Name,
ut.IsGood AS Status,
ut.SSNIndex AS RN
FROM PD_tbl_units_tracking ut WITH (NOLOCK)
INNER JOIN CS_idt_partnumbers pn ON ut.PartID = pn.PartID
INNER JOIN CS_idt_external_customers ec ON pn.CustomerID = ec.CustomerID
INNER JOIN PD_idt_areas a ON ut.AreaID = a.AreaID
INNER JOIN PD_idt_stations s ON ut.StationID = s.StationID
LEFT JOIN PART_BIN pb ON ut.PartID = pb.Part_ID AND ut.GroupMLS = pb.Bin_ID
WHERE ut.TrnDate BETWEEN @dateStart AND @dateEnd
AND (pn.PartID = @PartID OR @PartID=0)
AND (ut.AreaID = @AreaID OR @AreaID=0)
AND (ut.StationID = @StationID OR @StationID=0)
)
SELECT * FROM (SELECT * FROM w where w.rn = 1  and w.status='1') jz
", parameters);

          dtResult.Merge(dtAreaSTATIONPART);

          dtSerials.Merge(dtAreaSTATIONPART);
        }

