public ActionResult SuccessesSummary(DateTime? dateStart, DateTime? dateEnd, string selectedCustomers = "", string selectedPartNo = "", int StationID = 0, int AreaID = 0, int ssnindex = 1, bool execute = false, bool prepareDownload = false, string AreaName = "")
{

  var model = new Firstronic.Areas.Production.Models.Reports.ProductionSummary();

  model.dateStart = dateStart;

  if (dateStart is null)
  {
    model.dateStart = DateTime.Now;
  }

  model.dateEnd = dateEnd;

  if (dateEnd is null)
  {
    model.dateEnd = DateTime.Now;
  }

  model.selectedCustomers = selectedCustomers;

  model.selectedPartID = selectedPartNo;

  model.AreaID = AreaID;

  if (AreaName != "")
  {
    SqlParameter[] parameters = new SqlParameter[]
     {
        new SqlParameter("@Area",SqlDbType.VarChar){Value = AreaName}
     };

    model.AreaID = Firstronic.Framework.Queries.GetIntFromQuery("SELECT [AreaID] FROM [PART_OPERATION_AREAS] WHERE Area=@Area", parameters);
  }

  model.StationID = StationID;

  model.execute = execute;

  model.prepareDownload = prepareDownload;

  return View(model);
}

