    [HttpPost]
    public ActionResult HCtoBeFirst(HttpPostedFileBase file)
    {
      DataSet ds = new DataSet();
      if (Request.Files["file"].ContentLength > 0)
      {
        string fileExtension = System.IO.Path.GetExtension(Request.Files["file"].FileName);

        if (fileExtension == ".xls" || fileExtension == ".xlsx" || fileExtension == ".XLSX")
        {
          string fileLocation = Server.MapPath("~/Content/") + Request.Files["file"].FileName;
          if (System.IO.File.Exists(fileLocation))
          {

            System.IO.File.Delete(fileLocation);
          }
          Request.Files["file"].SaveAs(fileLocation);
          string excelConnectionString = string.Empty;
          excelConnectionString = "Provider=Microsoft.ACE.OLEDB.12.0;Data Source=" + fileLocation + ";Extended Properties=\"Excel 12.0;HDR=Yes;IMEX=2\"";
          //connection String for xls file format.
          if (fileExtension == ".xls")
          {
            excelConnectionString = "Provider=Microsoft.Jet.OLEDB.4.0;Data Source=" + fileLocation + ";Extended Properties=\"Excel 8.0;HDR=Yes;IMEX=2\"";
          }
          //connection String for xlsx file format.
          else if (fileExtension == ".xlsx")
          {

            excelConnectionString = "Provider=Microsoft.ACE.OLEDB.12.0;Data Source=" + fileLocation + ";Extended Properties=\"Excel 12.0;HDR=Yes;IMEX=2\"";
          }
          //Create Connection to Excel work book and add oledb namespace
          OleDbConnection excelConnection = new OleDbConnection(excelConnectionString);
          excelConnection.Open();
          DataTable dt = new DataTable();

          dt = excelConnection.GetOleDbSchemaTable(OleDbSchemaGuid.Tables, null);
          if (dt == null)
          {
            return null;
          }

          String[] excelSheets = new String[dt.Rows.Count];
          int t = 0;
          //excel data saves in temp file here.
          foreach (DataRow row in dt.Rows)
          {
            excelSheets[t] = row["TABLE_NAME"].ToString();
            t++;
          }
          OleDbConnection excelConnection1 = new OleDbConnection(excelConnectionString);


          string query = string.Format("Select * from [{0}]", excelSheets[0]);
          using (OleDbDataAdapter dataAdapter = new OleDbDataAdapter(query, excelConnection1))
          {
            dataAdapter.Fill(ds);
          }
        }
        if (fileExtension.ToString().ToLower().Equals(".xml"))
        {
          string fileLocation = Server.MapPath("~/Content/") + Request.Files["FileUpload"].FileName;
          if (System.IO.File.Exists(fileLocation))
          {
            System.IO.File.Delete(fileLocation);
          }

          Request.Files["FileUpload"].SaveAs(fileLocation);
          XmlTextReader xmlreader = new XmlTextReader(fileLocation);
          // DataSet ds = new DataSet();
          ds.ReadXml(xmlreader);
          xmlreader.Close();
        }
        int flag_Delte = 0;
        for (int i = 0; i < ds.Tables[0].Rows.Count; i++)
        {
          flag_Delte = i;
          string Numero = ds.Tables[0].Rows[i][0].ToString();

          int addcero = 9 - Numero.Length;
          String Gafete = "";

          for (int ii = 1; ii <= addcero; ii++)
          {
            Gafete = Gafete + "0";
          }

          Gafete = "R" + Gafete + ds.Tables[0].Rows[i][0].ToString() + "A";

          string ApellidoPaterno = ds.Tables[0].Rows[i][1].ToString().Replace("'", "");
          string ApellidoMaterno = ds.Tables[0].Rows[i][2].ToString().Replace("'", "");
          string Nombres = ds.Tables[0].Rows[i][3].ToString().Replace("'","");
          string Puesto = ds.Tables[0].Rows[i][4].ToString().Replace("'", "");
          string Confidencialidad = ds.Tables[0].Rows[i][5].ToString().Replace("'", "");
          string Productivo = ds.Tables[0].Rows[i][6].ToString().Replace("'", "");
          string Area = ds.Tables[0].Rows[i][7].ToString().Replace("'", "");
          string Supervisor = ""; // ds.Tables[0].Rows[i][8].ToString();
          string Turno = ""; //ds.Tables[0].Rows[i][9].ToString();
          string Tiempo = ""; //ds.Tables[0].Rows[i][10].ToString();
          string antiguedad = ""; //ds.Tables[0].Rows[i][11].ToString();
          string Proyecto = ""; //ds.Tables[0].Rows[i][12].ToString();
          string Genero = ""; //ds.Tables[0].Rows[i][13].ToString();
          string Ingreso = ""; //ds.Tables[0].Rows[i][14].ToString();

          //string query = "Insert into Person(Name,Email,Mobile) Values('" + ds.Tables[0].Rows[i][0].ToString() + "','" + ds.Tables[0].Rows[i][1].ToString() + "','" + ds.Tables[0].Rows[i][2].ToString() + "')";


          SMT.Load_HC_Bonus result = Firstronic.Framework.Functions.App.SMT.HC_Bonus_Add(Numero, ApellidoPaterno, ApellidoMaterno, Nombres, Puesto, Confidencialidad, Productivo, Area, Supervisor, Turno, Tiempo, antiguedad, Proyecto, Genero, Ingreso, flag_Delte, Gafete);

        }

      }
      return RedirectToAction("HCtoBeFirst", "Reports", new { Area = "Production" });

    }
  }
