              new SqlParameter("@dateEnd",SqlDbType.DateTime){Value =dateEnd.ToString("MM/dd/yyyy HH:mm:ss")}
                                                          };

          DataTable dtAreaSTATIONPART = Firstronic.Framework.Queries.GetDatatableFromQuery(@"WITH w AS (
                            SELECT
                            ut.SSN AS UnitID,
                            ut.TrnDate,
                            pn.PartNumber,
                            a.Area,
                            ec.CustomerName,
                            ut.JobSide,
                            ISNULL(pb.Bin_Name, '') AS Bin_Name,
                            ut.IsGood AS Status,
                            ut.SSNIndex AS RN
                            FROM PD_tbl_units_tracking ut WITH (NOLOCK)
                            INNER JOIN CS_idt_partnumbers pn ON ut.PartID = pn.PartID
                            INNER JOIN CS_idt_external_customers ec ON pn.CustomerID = ec.CustomerID
                            INNER JOIN PD_idt_areas a ON ut.AreaID = a.AreaID
                            INNER JOIN PD_idt_stations s ON ut.StationID = s.StationID
                            LEFT JOIN PART_BIN pb ON ut.PartID = pb.Part_ID AND ut.GroupMLS = pb.Bin_ID
                            WHERE ut.TrnDate BETWEEN @dateStart AND @dateEnd
                            AND (ut.AreaID = @AreaID OR @AreaID = 0)
                            AND (pn.CustomerID = @customerID OR @customerID = 0)
                            ),
