                            (FPY.Good + FPY.Bad) AS Total,
                            FPY.Good AS Good,
                            FPY.Bad AS Bad,
                            FORMAT(CASE WHEN (FPY.Good + FPY.Bad) > 0 THEN CAST(FPY.Good AS DECIMAL) / (FPY.Good + FPY.Bad) ELSE 0 END, 'P') AS FPY,
                            ISNULL(SPY.Good, 0) AS '2ndGood',
                            ISNULL(SPY.Bad, 0) AS '2ndBad',
                            FORMAT(CASE WHEN (SPY.Good + SPY.Bad) > 0 THEN CAST(SPY.Good AS DECIMAL) / (SPY.Good + SPY.Bad) ELSE 0 END, 'P') AS '2ndPY',
                            FPY.Good + ISNULL(SPY.Good, 0) AS AccumGood,
