                            AND FPY.JobSide = SGood.JobSide
                            AND FPY.Bin_Name = SGood.Bin_Name
                            LEFT JOIN total ON FPY.RN = total.RN
                            AND FPY.Area = total.Area
                            AND FPY.CustomerName = total.CustomerName
                            AND FPY.PartNumber = total.PartNumber
                            AND FPY.JobSide = total.JobSide
                            AND FPY.Bin_Name = total.Bin_Name;", parameters, "BeFirst:ConnectionString", 240);


