                      }
                      varcell1++;
                    }
                  }
                </tr>
              }
            </tbody>
          </table>
        </div>

        <script type="text/javascript" nonce="@Html.ScriptNonce()">
        // Get the grouped data from Razor
        var areas = @Html.Raw(areasJson);
        var counts = @Html.Raw(countsJson);

        // Create a chart
        var ctx = document.getElementById('myChart').getContext('2d');
        var myChart = new Chart(ctx, {
            type: 'bar', // You can change this to 'pie', 'line', etc.
            data: {
                labels: areas,
                datasets: [{
                    label: '# of Successes',
                    data: counts,
                    backgroundColor: 'rgba(75, 192, 75, 0.2)',
                    borderColor: 'rgba(75, 192, 75, 1)',
                    borderWidth: 1
                }]
            },
          options: {
                responsive: true,
                scales: {
                  yAxes: [{
                    id: 'y-axis-0',
                    gridLines: {
                      display: true,
                      lineWidth: 1,
                      color: "rgba(0,0,0,0.30)"
                    },
                    ticks: {
                      beginAtZero: true,
                      mirror: false,
                      suggestedMin: 0,
                    },
                    afterBuildTicks: function (chart) {

                    }
                  }],
                  xAxes: [{
                    id: 'x-axis-0',
                    gridLines: {
                      display: false
                    },
                    ticks: {
                      beginAtZero: true
                    }
                  }]
                },
              maintainAspectRatio: true,
            }
        });
        </script>

        <input id="btnExport" type="button" value="Export" class="md-btn md-btn-primary md-btn-mini uk-align-right mn-t-10 mn-b-0" />
      }
    }

  </div>
